import React, { useEffect, useState } from "react";
import { getCategory } from "../Redux/categories";
import { useDispatch, useSelector } from "react-redux";
import { ThreeCircles } from "react-loader-spinner";
import $ from "jquery";
import { Link } from "react-router-dom";
import { getSearchDetails } from "../Redux/search";
import { Helmet } from "react-helmet";

export default function PopularPeople() {
  const dispatch = useDispatch();
  const { allCategoryData, categoryIsLoading } = useSelector(
    (store) => store.categories
  );

  useEffect(() => {
    gotToPage();
    dispatch(
      getCategory({
        movieOrTvOrperson: "person",
        category: "popular",
        page: 1,
      })
    );
  }, [dispatch]);

  function gotToPage(element) {
    if (element === "<<") {
      let el = $(".active .page-link")[0];
      let value = $(el).text();

      if (Number(value) === 1) {
        return;
      } else {
        try {
          el.innerHTML = Number(value) - 1;
          dispatch(
            getCategory({
              movieOrTvOrperson: "person",
              category: "popular",
              page: Number(value) - 1,
            })
          );
        } catch (error) {
          console.log(error);
        }
      }
    } else {
      let el = $(".active .page-link")[0];
      let value = $(el).text();
      try {
        el.innerHTML = Number(value) + 1;
        dispatch(
          getCategory({
            movieOrTvOrperson: "person",
            category: "popular",
            page: Number(value) + 1,
          })
        );
      } catch (error) {
        console.log(error);
      }
    }
  }

  const { allSearchData, allSearchIsLoading } = useSelector(
    (store) => store.allSearch
  );
  const [inputValue, setinputValue] = useState(0);

  function search() {
    let value = $("#search").val();
    setinputValue(value);
    dispatch(getSearchDetails({ type: "person", value }));
  }

  return (
    <>
      <Helmet>
        <title>Popular People</title>
      </Helmet>
      <div className="container py-4 px-4">
        <h2 className="px-1 m-0 mb-4">Popular People</h2>
        <div className="search-input mb-5 position-relative">
          <input
            id="search"
            type="text"
            className="form-control"
            placeholder="Search for a person ..."
            onInput={() => search()}
          />
          <button>Search</button>
          {allSearchData.length === 0 && inputValue?.length > 0 ? (
            <h6 className="text-end w-100 py-2 text-danger position-absolute">
              no result found{" "}
            </h6>
          ) : (
            ""
          )}
        </div>
        <div className="row g-4 row-cols-xl-5">
          {inputValue?.length > 0 ? (
            <>
              {allSearchData.length > 0 ? (
                <>
                  {allSearchIsLoading ? (
                    <div className="d-flex justify-content-center align-items-center w-100">
                      <ThreeCircles
                        height="60"
                        width="60"
                        color="#1da161 "
                        wrapperStyle={{}}
                        wrapperClass=""
                        visible={true}
                        ariaLabel="three-circles-rotating"
                        outerCircleColor=""
                        innerCircleColor=""
                        middleCircleColor=""
                      />
                    </div>
                  ) : (
                    allSearchData?.map((item, idx) => (
                      <div
                        className="col-12 col-sm-6 col-md-4 col-lg-3 col-lg"
                        key={idx}
                      >
                        <Link
                          to={`/person/${item.id}`}
                          className="text-decoration-none text-white"
                        >
                          <div className="box">
                            <div className="img-box">
                              <div>
                                <img
                                  src={
                                    item.profile_path
                                      ? "https://image.tmdb.org/t/p/w220_and_h330_face/" +
                                        item.profile_path
                                      : require("../../Images/vNfL4DYnonltukBrrgMmw94zMYL.png")
                                  }
                                  alt=""
                                  className="w-100 "
                                />
                              </div>
                            </div>
                            <div className="details mt-4 text-dark text-center">
                              <h6>
                                {item.title === undefined
                                  ? item.name
                                  : item.title}
                              </h6>
                            </div>
                          </div>
                        </Link>
                      </div>
                    ))
                  )}
                </>
              ) : (
                <div className="d-flex justify-content-center align-items-center w-100 py-5">
                  <h3 className="text-center w-100">Not result found</h3>
                </div>
              )}
            </>
          ) : (
            <>
              {categoryIsLoading ? (
                <div className="d-flex justify-content-center align-items-center viewHeigth">
                  <ThreeCircles
                    height="60"
                    width="60"
                    color="#1da161 "
                    wrapperStyle={{}}
                    wrapperClass=""
                    visible={true}
                    ariaLabel="three-circles-rotating"
                    outerCircleColor=""
                    innerCircleColor=""
                    middleCircleColor=""
                  />
                </div>
              ) : (
                allCategoryData?.map((item, idx) => (
                  <div
                    className="col-12 col-sm-6 col-md-4 col-lg-3 col-lg"
                    key={idx}
                  >
                    <Link
                      to={`/person/${item.id}`}
                      className="text-decoration-none text-white"
                    >
                      <div className="box">
                        <div className="img-box">
                          <div>
                            <img
                              src={
                                "https://image.tmdb.org/t/p/w220_and_h330_face/" +
                                item.profile_path
                              }
                              alt=""
                              className="w-100"
                            />
                          </div>
                          {/* <div className="rate-container">
                      <div className="outer-border">
                        <div
                          className="progress"
                          style={{
                            background:
                              Math.round(item.vote_average * 10) >= 70
                                ? `conic-gradient(#1da161 ${
                                    item.vote_average * 10 * 3.6
                                  }deg, #1da1618c 0%)`
                                : `conic-gradient(#d2d531 ${
                                    item.vote_average * 10 * 3.6
                                  }deg, #423d0f 0%)`,
                          }}
                        >
                          <span className="rate">
                            {Math.round(item.vote_average * 10)} <sup>%</sup>
                          </span>
                        </div>
                      </div>
                    </div> */}
                        </div>
                        <div className="details mt-4 text-dark text-center">
                          <h6>
                            {item.title === undefined ? item.name : item.title}
                          </h6>
                          {/* <span className="lead fs-6">
                        {item.known_for[0].title}
                      </span> */}
                        </div>
                      </div>
                    </Link>
                  </div>
                ))
              )}
              <nav aria-label="Page navigation example " className="w-100 pt-5">
                <ul className="pagination justify-content-center">
                  <li className="page-item" onClick={() => gotToPage("<<")}>
                    <span className="page-link" aria-label="Previous">
                      <span aria-hidden="true">&laquo;</span>
                    </span>
                  </li>
                  <li className="page-item active">
                    <span className="page-link">1</span>
                  </li>

                  <li className="page-item" onClick={() => gotToPage(">>")}>
                    <span className="page-link" aria-label="Next">
                      <span aria-hidden="true">&raquo;</span>
                    </span>
                  </li>
                </ul>
              </nav>
            </>
          )}
        </div>
      </div>
    </>
  );
}
