import React, { useEffect } from "react";
import logo from "../../Images/movie-camera.png";
import $ from "../../../node_modules/jquery/dist/jquery.min.js";
import "./Navbar.scss";
import { Link } from "react-router-dom";

export default function Navbar() {
  function stepOne() {
    $(".nav-link").click(function () {
      // check if section is display then hide him and vice verse (in small screen)
      // $(".nav-link").not(this).css("color" , "#fff")
      // $(this).css("color" , "red")

      if ($(this).siblings().css("display") === "none") {
        // for close all menu
        $(".nav-link")
          .siblings()
          .css({ display: "none", position: "absolute", width: "170px" });

        $(this)
          .siblings()
          .css({ display: "block", position: "relative", width: "100%" });
      } else {
        $(this)
          .siblings()
          .css({ display: "none", position: "absolute", width: "170px" });
      }
    });
  }

  function stepTwo() {
    // for set default properties in larger screen
    $(window).resize(function () {
      if (this.innerWidth >= 992) {
        $(".section-dropdown").css({
          display: "none",
          position: "absolute",
          width: "170px",
        });
      }
    });
  }

  function stepThree() {
    // navbar show and disapper
    let prevScrollPos = window.pageYOffset;
    $(window).scroll(function () {
      const currentScrollPos = window.pageYOffset;

      if (prevScrollPos > currentScrollPos) {
        // user has scrolled up
        $(".navbar").css("top", 0);
        // $(".navbar").css("opacity", 1);
      } else {
        // user has scrolled down

        // for make navbar-collapse wait .5s before disappear and then make it close
        setTimeout(() => {
          $(".navbar-collapse").removeClass("show");
        }, 500);
        $(".navbar").css("top", `-${$(".navbar").innerHeight()}px`);
        // $(".navbar").css("opacity", 0);
      }

      // update previous scroll position
      prevScrollPos = currentScrollPos;
    });
  }

  useEffect(() => {
    stepOne();
    stepTwo();
    stepThree();
  });
  return (
    <>
      <nav className="navbar navbar-expand-lg p-0">
        <div className="nav-container container-fluid container-xxl">
          <Link className="navbar-brand" to="/">
            <img src={logo} alt="logo icon" />
            <span className="ms-1 fw-semibold">NOX</span>
          </Link>
          <button
            className="navbar-toggler"
            type="button"
            data-bs-toggle="collapse"
            data-bs-target="#navbarSupportedContent"
            aria-controls="navbarSupportedContent"
            aria-expanded="false"
            aria-label="Toggle navigation"
          >
            <i className="fa-solid fa-bars"></i>
          </button>
          <div className="collapse navbar-collapse" id="navbarSupportedContent">
            <ul className="navbar-nav ms-auto mb-2 mb-lg-0">
              <li className="nav-item section-link">
                <a className="nav-link" aria-current="page">
                  Movies
                </a>
                <ul className="list-unstyled section-dropdown ">
                  <li className="lead">
                    <Link to="/popularMovie">Popular</Link>
                  </li>
                  <li className="lead">
                    <Link to="/nowPlayingMovie">Now Playing</Link>
                  </li>
                  <li className="lead">
                    <Link to="/upComingMovie">Upcoming</Link>
                  </li>
                  <li className="lead">
                    <Link to="/topRatedMovie">Top Rated</Link>
                  </li>
                </ul>
              </li>
              <li className="nav-item section-link">
                <a className="nav-link">TV Shows</a>
                <ul className="list-unstyled section-dropdown">
                  <li className="lead">
                    <Link to="/popularTv">Popular</Link>
                  </li>
                  <li className="lead">
                    <Link to="/airingTodayTv">Airing Today</Link>
                  </li>
                  <li className="lead">
                    <Link to="/onTV">On TV</Link>
                  </li>
                  <li className="lead">
                    <Link to="/topRatedTv">Top Rated</Link>
                  </li>
                </ul>
              </li>
              <li className="nav-item section-link">
                <a className="nav-link">People</a>
                <ul className="list-unstyled section-dropdown">
                  <li className="lead">
                    <Link to="/popularPeople">Popular People</Link>
                  </li>
                </ul>
              </li>
            </ul>
          </div>
        </div>
      </nav>
    </>
  );
}
